// AI Engine Logic
const calculateLSTMNextStep = (prevVal: number, drift: number, volatility: number, momentum: number): { val: number, momentum: number } => {
    const noise = randomNormal(0, volatility);
    const newMomentum = (momentum * 0.7) + (drift * 0.3) + (noise * 0.1); 
    const step = newMomentum * prevVal;
    return { val: prevVal + step, momentum: newMomentum };
};

const calculateBoostingNextStep = (prevVal: number, drift: number, volatility: number): number => {
    const noise = randomNormal(0, volatility);
    let jump = 0;
    if (Math.random() > 0.85) jump = (Math.random() - 0.5) * volatility * 3.0;
    return prevVal * (1 + drift + noise + jump);
};

const calculateStandardNextStep = (prevVal: number, drift: number, volatility: number): number => {
    const noise = randomNormal(0, volatility);
    return prevVal * (1 + drift + noise);
};

export const runSimulation = (
  historyData: DataPoint[], 
  config: SimulationConfig
): { alt1: DataPoint[], alt2: DataPoint[], alt3: DataPoint[], metrics: SimulationMetrics } => {
  const alt1: DataPoint[] = []; 
  const alt2: DataPoint[] = []; 
  const alt3: DataPoint[] = []; 

  if (!historyData || historyData.length === 0) return { alt1, alt2, alt3, metrics: { worstCAGR: 0, moderateCAGR: 0, bestCAGR: 0 } };

  const lastPoint = historyData[historyData.length - 1];
  const startValue = lastPoint.value;
  const startDate = new Date(lastPoint.timestamp);
  const toWeeklyRate = (annualRate: number) => Math.pow(1 + annualRate, 1/52) - 1;

  let annualBaseGrowth = 0.08; 
  let volatilityRef = 0.04; 
  switch (config.referenceMarket) {
    case 'Japan': annualBaseGrowth = 0.09; volatilityRef = 0.04; break;
    case 'SP500': annualBaseGrowth = 0.10; volatilityRef = 0.035; break;
    case 'NASDAQ': annualBaseGrowth = 0.14; volatilityRef = 0.055; break;
    case 'DowJones': annualBaseGrowth = 0.085; volatilityRef = 0.03; break;
  }

  const RISK_FREE_RATE = 0.035;
  const SMB_PREMIUM = 0.030;
  const RMW_PREMIUM = 0.035;
  const CMA_PREMIUM = 0.030;
  const HML_PREMIUM = 0.040;
  const QMJ_PREMIUM = 0.045; // Quality Premium
  const POLICY_PREMIUM = 0.025; 

  const marketPremium = annualBaseGrowth - RISK_FREE_RATE;
  const simVol = (volatilityRef / 2.0) * (config.volatility / 5.0);
  const totalWeeks = Math.floor(config.durationMonths * 4.345); 

  let val1 = startValue, val2 = startValue, val3 = startValue;
  let m1 = 0, m2 = 0, m3 = 0;

  // --- 7-Factor Implementation ---
  // E(R) = Rf + b(Mkt) + s(SMB) + h(HML) + r(RMW) + c(CMA) + q(QMJ) + p(Policy)

  // Worst: Low Quality, No Policy, High Risk, Value Trap
  const wAnn = RISK_FREE_RATE + (0.8 * marketPremium) - (0.5 * SMB_PREMIUM) - (0.5 * HML_PREMIUM) - (0.5 * RMW_PREMIUM) - (0.5 * CMA_PREMIUM) - (0.8 * QMJ_PREMIUM);
  const wDrift = toWeeklyRate(wAnn - 0.02);

  // Moderate: User weights
  const mAnn = RISK_FREE_RATE + 
               (config.betaWeight * marketPremium) + 
               (config.smbWeight * SMB_PREMIUM) + 
               (config.hmlWeight * HML_PREMIUM) + 
               (config.rmwWeight * RMW_PREMIUM) + 
               (config.cmaWeight * CMA_PREMIUM) + 
               (config.qmjWeight * QMJ_PREMIUM) + 
               (config.policyWeight * POLICY_PREMIUM);
  const mDrift = toWeeklyRate(mAnn);

  // Best: Optimization + Policy Success
  const bAnn = RISK_FREE_RATE + 
               (Math.max(1.2, config.betaWeight) * marketPremium) + 
               (Math.max(0.5, config.smbWeight) * SMB_PREMIUM) + 
               (config.hmlWeight * HML_PREMIUM) + 
               (Math.max(1.0, config.rmwWeight) * RMW_PREMIUM) + 
               (Math.max(1.0, config.cmaWeight) * CMA_PREMIUM) + 
               (Math.max(1.2, config.qmjWeight) * QMJ_PREMIUM) + 
               (Math.max(0.9, config.policyWeight) * POLICY_PREMIUM);
  const bDrift = toWeeklyRate(bAnn + 0.015);

  const metrics: SimulationMetrics = { worstCAGR: wAnn - 0.02, moderateCAGR: mAnn, bestCAGR: bAnn + 0.015 };

  for (let i = 1; i <= totalWeeks; i++) {
    const newDate = new Date(startDate);
    newDate.setDate(startDate.getDate() + (i * 7));
    const dStr = formatDate(newDate); 
    const ts = newDate.getTime();

    if (config.modelType === 'LSTM' || config.modelType === 'GRU') {
        const r1 = calculateLSTMNextStep(val1, wDrift, simVol * 0.8, m1); val1 = r1.val; m1 = r1.momentum;
        const r2 = calculateLSTMNextStep(val2, mDrift, simVol * 0.8, m2); val2 = r2.val; m2 = r2.momentum;
        const r3 = calculateLSTMNextStep(val3, bDrift, simVol * 0.8, m3); val3 = r3.val; m3 = r3.momentum;
    } else if (config.modelType === 'XGBoost') {
        val1 = calculateBoostingNextStep(val1, wDrift, simVol * 1.2);
        val2 = calculateBoostingNextStep(val2, mDrift, simVol * 1.2);
        val3 = calculateBoostingNextStep(val3, bDrift, simVol * 1.2);
    } else {
        val1 = calculateStandardNextStep(val1, wDrift, simVol);
        val2 = calculateStandardNextStep(val2, mDrift, simVol);
        val3 = calculateStandardNextStep(val3, bDrift, simVol);
    }

    alt1.push({ date: dStr, timestamp: ts, value: val1, ratio: val1 / startValue, type: 'Prediction', marketName: 'Worst Case', scenario: 'alt1_worst' });
    alt2.push({ date: dStr, timestamp: ts, value: val2, ratio: val2 / startValue, type: 'Prediction', marketName: 'Moderate Case', scenario: 'alt2_moderate' });
    alt3.push({ date: dStr, timestamp: ts, value: val3, ratio: val3 / startValue, type: 'Prediction', marketName: 'Best Case', scenario: 'alt3_best' });
  }

  return { alt1, alt2, alt3, metrics };
};

