interface ErrorBoundaryProps { children?: ReactNode; }
interface ErrorBoundaryState { hasError: boolean; }

// Use Component directly from react to ensure proper type inheritance for props and state
// This fix addresses the errors on lines 15, 21, and 22 where 'state' and 'props' were not recognized
class ErrorBoundary extends Component<ErrorBoundaryProps, ErrorBoundaryState> {
  constructor(props: ErrorBoundaryProps) {
    super(props);
    // Initialize state on the class instance inherited from Component
    this.state = { hasError: false };
  }

  static getDerivedStateFromError(_: Error): ErrorBoundaryState { return { hasError: true }; }

  render() {
    // Correctly access state and props via the inherited Component class
    if (this.state.hasError) return <div className="p-10 text-center text-red-600 font-bold">CRITICAL ERROR: Please refresh simulation.</div>;
    return this.props.children;
  }
}

