interface ErrorBoundaryProps { children?: ReactNode; }
interface ErrorBoundaryState { hasError: boolean; }

// Use React.Component and property initializer to resolve 'state' and 'props' not recognized errors
class ErrorBoundary extends React.Component<ErrorBoundaryProps, ErrorBoundaryState> {
  // Use property initializer for state to avoid constructor-related inheritance issues in some TS environments
  state: ErrorBoundaryState = { hasError: false };

  static getDerivedStateFromError(_: Error): ErrorBoundaryState { 
    return { hasError: true }; 
  }

  render() {
    // Correctly access state and props via the inherited React.Component class
    if (this.state.hasError) {
      return <div className="p-10 text-center text-red-600 font-bold">CRITICAL ERROR: Please refresh simulation.</div>;
    }
    return this.props.children;
  }
}

