// AI Engine Logic
const calculateLSTMNextStep = (prevVal: number, drift: number, volatility: number, momentum: number): { val: number, momentum: number } => {
    const noise = randomNormal(0, volatility);
    const newMomentum = (momentum * 0.7) + (drift * 0.3) + (noise * 0.1); 
    const step = newMomentum * prevVal;
    return { val: prevVal + step, momentum: newMomentum };
};

const calculateBoostingNextStep = (prevVal: number, drift: number, volatility: number): number => {
    const noise = randomNormal(0, volatility);
    let jump = 0;
    if (Math.random() > 0.85) jump = (Math.random() - 0.5) * volatility * 3.0;
    return prevVal * (1 + drift + noise + jump);
};

const calculateStandardNextStep = (prevVal: number, drift: number, volatility: number): number => {
    const noise = randomNormal(0, volatility);
    return prevVal * (1 + drift + noise);
};

export const runSimulation = (
  historyData: DataPoint[], 
  config: SimulationConfig
): { alt1: DataPoint[], alt2: DataPoint[], alt3: DataPoint[], metrics: SimulationMetrics } => {
  const alt1: DataPoint[] = []; 
  const alt2: DataPoint[] = []; 
  const alt3: DataPoint[] = []; 

  if (!historyData || historyData.length === 0) return { alt1, alt2, alt3, metrics: { worstCAGR: 0, moderateCAGR: 0, bestCAGR: 0 } };

  const lastPoint = historyData[historyData.length - 1];
  const startValue = lastPoint.value;
  const startDate = new Date(lastPoint.timestamp);
  const toWeeklyRate = (annualRate: number) => Math.pow(1 + annualRate, 1/52) - 1;

  let annualBaseGrowth = 0.08; 
  let volatilityRef = 0.04; 
  switch (config.referenceMarket) {
    case 'Japan': annualBaseGrowth = 0.09; volatilityRef = 0.04; break;
    case 'Taiwan': annualBaseGrowth = 0.11; volatilityRef = 0.05; break;
    case 'SP500': annualBaseGrowth = 0.10; volatilityRef = 0.035; break;
    case 'NASDAQ': annualBaseGrowth = 0.14; volatilityRef = 0.055; break;
    case 'DowJones': annualBaseGrowth = 0.085; volatilityRef = 0.03; break;
    case 'Germany': annualBaseGrowth = 0.08; volatilityRef = 0.04; break;
  }

  const RISK_FREE_RATE = 0.035;
  const SMB_PREMIUM = 0.030;
  const RMW_PREMIUM = 0.035;
  const CMA_PREMIUM = 0.030;
  const HML_PREMIUM = 0.040;
  const QMJ_PREMIUM = 0.045; 
  const POLICY_PREMIUM = 0.025; 

  const marketPremium = annualBaseGrowth - RISK_FREE_RATE;
  const simVol = (volatilityRef / 2.0) * (config.volatility / 5.0);
  const totalWeeks = Math.floor(config.durationMonths * 4.345); 

  let val1 = startValue, val2 = startValue, val3 = startValue;
  let m1 = 0, m2 = 0, m3 = 0;

  const isFiveFactor = config.modelType === 'FamaFrench5';
  const effectiveQmjWeight = isFiveFactor ? 0 : config.qmjWeight;
  const effectivePolicyWeight = isFiveFactor ? 0 : config.policyWeight;

  const wAnn = RISK_FREE_RATE + (0.8 * marketPremium) - (0.5 * SMB_PREMIUM) - (0.5 * HML_PREMIUM) - (0.5 * RMW_PREMIUM) - (0.5 * CMA_PREMIUM) - (isFiveFactor ? 0 : 0.8 * QMJ_PREMIUM);
  const wDrift = toWeeklyRate(wAnn - 0.02);

  const mAnn = RISK_FREE_RATE + (config.betaWeight * marketPremium) + (config.smbWeight * SMB_PREMIUM) + (config.hmlWeight * HML_PREMIUM) + (config.rmwWeight * RMW_PREMIUM) + (config.cmaWeight * CMA_PREMIUM) + (effectiveQmjWeight * QMJ_PREMIUM) + (effectivePolicyWeight * POLICY_PREMIUM);
  const mDrift = toWeeklyRate(mAnn);

  const bAnn = RISK_FREE_RATE + (Math.max(1.2, config.betaWeight) * marketPremium) + (Math.max(0.5, config.smbWeight) * SMB_PREMIUM) + (config.hmlWeight * HML_PREMIUM) + (Math.max(1.0, config.rmwWeight) * RMW_PREMIUM) + (Math.max(1.0, config.cmaWeight) * CMA_PREMIUM) + (isFiveFactor ? 0 : Math.max(1.2, config.qmjWeight) * QMJ_PREMIUM) + (isFiveFactor ? 0 : Math.max(0.9, config.policyWeight) * POLICY_PREMIUM);
  const bDrift = toWeeklyRate(bAnn + 0.015);

  const metrics: SimulationMetrics = { worstCAGR: wAnn - 0.02, moderateCAGR: mAnn, bestCAGR: bAnn + 0.015 };

  for (let i = 1; i <= totalWeeks; i++) {
    const newDate = new Date(startDate);
    newDate.setDate(startDate.getDate() + (i * 7));
    const dStr = formatDate(newDate); 
    const ts = newDate.getTime();

    if (config.modelType === 'LSTM' || config.modelType === 'GRU') {
        const r1 = calculateLSTMNextStep(val1, wDrift, simVol * 0.8, m1); val1 = r1.val; m1 = r1.momentum;
        const r2 = calculateLSTMNextStep(val2, mDrift, simVol * 0.8, m2); val2 = r2.val; m2 = r2.momentum;
        const r3 = calculateLSTMNextStep(val3, bDrift, simVol * 0.8, m3); val3 = r3.val; m3 = r3.momentum;
    } else if (config.modelType === 'XGBoost' || config.modelType === 'LightGBM') {
        const boostVol = config.modelType === 'LightGBM' ? simVol * 1.1 : simVol * 1.2;
        val1 = calculateBoostingNextStep(val1, wDrift, boostVol);
        val2 = calculateBoostingNextStep(val2, mDrift, boostVol);
        val3 = calculateBoostingNextStep(val3, bDrift, boostVol);
    } else {
        val1 = calculateStandardNextStep(val1, wDrift, simVol);
        val2 = calculateStandardNextStep(val2, mDrift, simVol);
        val3 = calculateStandardNextStep(val3, bDrift, simVol);
    }

    alt1.push({ date: dStr, timestamp: ts, value: val1, ratio: val1 / startValue, type: 'Prediction', marketName: 'Worst Case', scenario: 'alt1_worst' });
    alt2.push({ date: dStr, timestamp: ts, value: val2, ratio: val2 / startValue, type: 'Prediction', marketName: 'Moderate Case', scenario: 'alt2_moderate' });
    alt3.push({ date: dStr, timestamp: ts, value: val3, ratio: val3 / startValue, type: 'Prediction', marketName: 'Best Case', scenario: 'alt3_best' });
  }

  return { alt1, alt2, alt3, metrics };
};

import React, { useMemo } from 'react';
import {
  LineChart,
  Line,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  Legend,
  ResponsiveContainer,
  ReferenceLine,
  ReferenceArea
} from 'recharts';
import { DataPoint, ReferenceMarket, TargetIndex } from '../types';

interface SimulationChartProps {
  historyData: DataPoint[];
  alt1Data: DataPoint[];
  alt2Data: DataPoint[];
  alt3Data: DataPoint[];
  referenceData: DataPoint[];
  referenceMarket: ReferenceMarket;
  targetIndex: TargetIndex;
}

const GenericLabel = (props: any) => {
  const { x, y, value, payload, index, stroke, title, isRef, actualRefVal, lastTimestamp, midTimestamp } = props;
  if (x === undefined || y === undefined || !payload) return null;

  const dateStr = payload.date || "";
  const dateParts = dateStr.split('-');
  const year = parseInt(dateParts[0]);
  const month = parseInt(dateParts[1]);
  const day = parseInt(dateParts[2]);

  const isStart = index === 0;
  const isLast = payload.timestamp === lastTimestamp;
  const isMiddle = midTimestamp && payload.timestamp === midTimestamp;

  const isPeriodic = month === 1 && day <= 14 && year % 2 === 0;

  if (!isStart && !isLast && !isMiddle && !isPeriodic) return null;

  const valToShow = isRef ? (actualRefVal ?? value) : value;
  const displayVal = Math.round(valToShow).toLocaleString();
  const dyVal = isRef ? -25 : 30; 

  return (
    <g>
      <circle cx={x} cy={y} r={isStart || isLast ? 4 : 3} fill={stroke} stroke="#fff" strokeWidth={2} />
      <text x={x} y={y} dy={dyVal} stroke="#fff" strokeWidth={4} strokeLinecap="round" strokeLinejoin="round" fontSize={12} fontWeight="900" textAnchor="middle">{displayVal}</text>
      <text x={x} y={y} dy={dyVal} fill={stroke} fontSize={12} fontWeight="900" textAnchor="middle">{displayVal}</text>
      <text x={x} y={y} dy={dyVal + 12} fill="#64748b" fontSize={9} fontWeight="700" textAnchor="middle">{isLast ? 'Now' : year}</text>
    </g>
  );
};

const ForecastLabel = (props: any) => {
  const { x, y, value, payload, stroke, lastTimestamp, orientation = 'top', periodicTimestamps } = props;
  if (x === undefined || y === undefined || !payload) return null;

  const dateParts = (payload.date || "").split('-');
  const year = parseInt(dateParts[0]);
  const isLast = payload.timestamp === lastTimestamp;
  const isPeriodic = periodicTimestamps && periodicTimestamps.has(payload.timestamp);

  if (!isLast && !isPeriodic) return null;

  const displayVal = Math.round(value).toLocaleString();
  const dyVal = orientation === 'top' ? -10 : 20;

  return (
    <g>
      <circle cx={x} cy={y} r={isLast ? 3.5 : 2.5} fill={stroke} stroke="#fff" strokeWidth={1} />
      <rect x={x - 22} y={y + dyVal - 12} width={44} height={16} rx={4} fill="white" stroke={stroke} strokeWidth={1} opacity={0.9} />
      <text x={x} y={y} dy={dyVal} fill={stroke} fontSize={10} fontWeight="800" textAnchor="middle" alignmentBaseline="middle">{displayVal}</text>
      {isLast && <text x={x} y={y} dy={dyVal + (orientation === 'top' ? -12 : 24)} fill={stroke} fontSize={8} fontWeight="bold" textAnchor="middle">Final</text>}
    </g>
  );
};

const SimulationChart: React.FC<SimulationChartProps> = ({
  historyData, alt1Data, alt2Data, alt3Data, referenceData, referenceMarket, targetIndex
}) => {
  const lastHistoryTs = historyData.length > 0 ? historyData[historyData.length - 1].timestamp : 0;
  const lastRefTs = referenceData.length > 0 ? referenceData[referenceData.length - 1].timestamp : 0;
  const lastForecastTs = alt1Data.length > 0 ? alt1Data[alt1Data.length - 1].timestamp : 0;
  const midHistoryTs = historyData.length > 0 ? historyData[Math.floor(historyData.length / 2)].timestamp : 0;

  const forecastPeriodicTimestamps = useMemo(() => {
    const set = new Set<number>();
    const seenYears = new Set<number>();
    if (alt1Data) {
      alt1Data.forEach(d => {
        const year = parseInt(d.date.split('-')[0]);
        if (year % 2 === 0 && !seenYears.has(year)) {
          seenYears.add(year);
          set.add(d.timestamp);
        }
      });
    }
    return set;
  }, [alt1Data]);

  const chartData = useMemo(() => {
    const dataMap = new Map<number, any>();
    const process = (data: DataPoint[], key: string, isRef = false) => {
      data.forEach(pt => {
        if (!dataMap.has(pt.timestamp)) {
          dataMap.set(pt.timestamp, { date: pt.date, timestamp: pt.timestamp });
        }
        const entry = dataMap.get(pt.timestamp);
        if (isRef) entry[`reference_actual`] = pt.value;
        else entry[key] = pt.value;
      });
    };
    process(referenceData, 'reference', true);
    process(historyData, 'history');
    process(alt1Data, 'alt1');
    process(alt2Data, 'alt2');
    process(alt3Data, 'alt3');
    return Array.from(dataMap.values()).sort((a, b) => a.timestamp - b.timestamp);
  }, [referenceData, historyData, alt1Data, alt2Data, alt3Data]);

  const ticks = useMemo(() => {
    return chartData
      .filter(d => {
        const p = d.date.split('-');
        return p[1] === '01' && parseInt(p[2]) <= 14;
      })
      .map(d => d.timestamp)
      .filter((ts, idx, self) => {
        const year = new Date(ts).getFullYear();
        return self.findIndex(t => new Date(t).getFullYear() === year) === idx;
      });
  }, [chartData]);

  const CustomTooltip = ({ active, payload, label }: any) => {
    if (active && payload && payload.length) {
      const date = new Date(label).toLocaleDateString('en-US', { year: 'numeric', month: 'short' });
      return (
        <div className="bg-white/95 border border-slate-200 p-3 rounded shadow-xl text-xs backdrop-blur-sm z-50">
          <p className="font-bold border-b border-slate-100 pb-1 mb-2 text-slate-800">{date}</p>
          {payload.map((entry: any, i: number) => (
            <div key={i} className="flex items-center justify-between gap-4 mb-1">
              <span className="flex items-center gap-2 text-slate-600">
                <span className="w-2 h-2 rounded-full" style={{ background: entry.color }}></span>
                {entry.dataKey === 'reference_actual' ? referenceMarket : entry.name}:
              </span>
              <span className="font-mono font-bold text-slate-800">{Math.round(entry.value).toLocaleString()}</span>
            </div>
          ))}
        </div>
      );
    }
    return null;
  };

  return (
    <div className="bg-white p-2 md:p-4 rounded-xl border border-slate-200 shadow-sm h-[520px]">
      <ResponsiveContainer width="100%" height="100%">
        <LineChart data={chartData} margin={{ top: 40, right: 30, left: 10, bottom: 20 }}>
          <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
          <XAxis 
            dataKey="timestamp" 
            type="number"
            scale="time"
            domain={['dataMin', 'dataMax']}
            ticks={ticks}
            tickFormatter={(ts) => new Date(ts).getFullYear().toString()} 
            tick={{ fontSize: 10, fill: '#94a3b8' }} 
          />
          <YAxis yAxisId="left" domain={['auto', 'auto']} tick={{ fontSize: 10, fill: '#0f172a', fontWeight: 600 }} width={40} />
          <YAxis yAxisId="right" orientation="right" domain={['auto', 'auto']} tick={{ fontSize: 10, fill: '#94a3b8' }} width={40} />
          <Tooltip content={<CustomTooltip />} />
          <Legend wrapperStyle={{ paddingTop: '15px', fontSize: '11px' }} />

          <Line yAxisId="right" type="monotone" dataKey="reference_actual" name={`${referenceMarket} (Ref)`} stroke="#cbd5e1" strokeWidth={1.5} strokeDasharray="3 3" dot={false} connectNulls label={(p) => <GenericLabel {...p} stroke="#94a3b8" isRef={true} lastTimestamp={lastRefTs} />} />
          <Line yAxisId="left" type="monotone" dataKey="history" name={`${targetIndex} History`} stroke="#0f172a" strokeWidth={2} dot={false} connectNulls label={(p) => <GenericLabel {...p} stroke="#0f172a" isRef={false} lastTimestamp={lastHistoryTs} midTimestamp={midHistoryTs} />} />
          <Line yAxisId="left" type="monotone" dataKey="alt1" name="Worst" stroke="#ef4444" strokeWidth={1.5} strokeDasharray="4 4" dot={false} label={(p) => <ForecastLabel {...p} stroke="#ef4444" lastTimestamp={lastForecastTs} orientation="bottom" periodicTimestamps={forecastPeriodicTimestamps} />} />
          <Line yAxisId="left" type="monotone" dataKey="alt2" name="Moderate" stroke="#3b82f6" strokeWidth={2} dot={false} label={(p) => <ForecastLabel {...p} stroke="#3b82f6" lastTimestamp={lastForecastTs} orientation="top" periodicTimestamps={forecastPeriodicTimestamps} />} />
          <Line yAxisId="left" type="monotone" dataKey="alt3" name="Best" stroke="#22c55e" strokeWidth={2} dot={false} label={(p) => <ForecastLabel {...p} stroke="#22c55e" lastTimestamp={lastForecastTs} orientation="top" periodicTimestamps={forecastPeriodicTimestamps} />} />

          {alt1Data.length > 0 && (
             <ReferenceArea yAxisId="left" x1={alt1Data[0].timestamp} x2={alt1Data[alt1Data.length - 1].timestamp} fill="#f8fafc" fillOpacity={0.4} label={{ value: "FORECAST", position: "insideTopLeft", fill: "#94a3b8", fontSize: 10, fontWeight: 800, dy: 10, dx: 10 }} />
          )}
          {alt1Data.length > 0 && <ReferenceLine yAxisId="left" x={alt1Data[0].timestamp} stroke="#cbd5e1" strokeDasharray="3 3" />}
        </LineChart>
      </ResponsiveContainer>
    </div>
  );
};

