import React, { Component, useState, useEffect, useCallback, ReactNode } from 'react';
import { generateAllMarketData, runSimulation } from './services/dataService';
import SimulationChart from './components/SimulationChart';
import ControlPanel from './components/ControlPanel';
import { DataPoint, SimulationConfig, SimulationMetrics } from './types';

// Error Boundary
interface ErrorBoundaryProps { children?: ReactNode; }
interface ErrorBoundaryState { hasError: boolean; }

class ErrorBoundary extends Component<ErrorBoundaryProps, ErrorBoundaryState> {
  constructor(props: ErrorBoundaryProps) {
    super(props);
    this.state = { hasError: false };
  }

  static getDerivedStateFromError(_: Error): ErrorBoundaryState { 
    return { hasError: true }; 
  }

  render() {
    if (this.state.hasError) {
      return <div className="p-10 text-center text-red-600 font-bold">CRITICAL ERROR: Please refresh simulation.</div>;
    }
    return this.props.children;
  }
}

const AppContent = () => {
  const [loading, setLoading] = useState(true);
  const [datasets, setDatasets] = useState<any>(null);

  const [config, setConfig] = useState<SimulationConfig>({
    betaWeight: 1.0, 
    smbWeight: 0.1,  
    hmlWeight: 1.0,  
    rmwWeight: 1.0,  
    cmaWeight: 1.0,  
    qmjWeight: 1.0,  
    policyWeight: 0.5,
    volatility: 4,
    durationMonths: 60,
    referenceMarket: 'Japan',
    targetIndex: 'KOSPI',
    historyCutoffYear: 2025,
    modelType: 'FamaFrench5'
  });

  const [simResults, setSimResults] = useState<{
    targetIndex: string;
    alt1: DataPoint[];
    alt2: DataPoint[];
    alt3: DataPoint[];
    metrics?: SimulationMetrics;
  }>({ targetIndex: 'KOSPI', alt1: [], alt2: [], alt3: [] });

  useEffect(() => {
    const data = generateAllMarketData();
    setDatasets(data);
    setLoading(false);
  }, []);

  const runSim = useCallback((currentDatasets: any, currentConfig: SimulationConfig) => {
    if (!currentDatasets) return;
    const fullHistory: DataPoint[] = currentConfig.targetIndex === 'KOSPI' ? currentDatasets.kospiData : currentDatasets.kosdaqData;
    const effectiveHistory = fullHistory.filter((pt: DataPoint) => {
        const year = parseInt(pt.date.split('-')[0]);
        return year <= currentConfig.historyCutoffYear;
    });
    const results = runSimulation(effectiveHistory, currentConfig);
    setSimResults({
      targetIndex: currentConfig.targetIndex,
      alt1: results.alt1,
      alt2: results.alt2,
      alt3: results.alt3,
      metrics: results.metrics
    });
  }, []);

  const handleManualRun = () => runSim(datasets, config);

  useEffect(() => {
    if (datasets) runSim(datasets, config);
  }, [
      datasets, config.targetIndex, config.referenceMarket, config.historyCutoffYear, 
      config.modelType, config.betaWeight, config.smbWeight, config.hmlWeight, 
      config.rmwWeight, config.cmaWeight, config.qmjWeight, config.policyWeight
  ]); 

  if (loading || !datasets) return <div className="h-screen flex items-center justify-center text-indigo-600 font-bold animate-pulse">Initializing 7-Factor Engine...</div>;

  const fullHistory = config.targetIndex === 'KOSPI' ? datasets.kospiData : datasets.kosdaqData;
  const currentHistory = fullHistory.filter((pt: DataPoint) => parseInt(pt.date.split('-')[0]) <= config.historyCutoffYear);

  const currentReference = (() => {
    switch(config.referenceMarket) {
      case 'Japan': return datasets.japanData;
      case 'Taiwan': return datasets.taiwanData;
      case 'SP500': return datasets.sp500Data;
      case 'NASDAQ': return datasets.nasdaqData;
      case 'DowJones': return datasets.dowData;
      case 'Germany': return datasets.germanyData;
      default: return datasets.japanData;
    }
  })();

  const isDataSynced = simResults.targetIndex === config.targetIndex;
  const safeAlt1 = isDataSynced ? simResults.alt1 : [];
  const safeAlt2 = isDataSynced ? simResults.alt2 : [];
  const safeAlt3 = isDataSynced ? simResults.alt3 : [];
  const safeMetrics = isDataSynced && simResults.metrics ? simResults.metrics : { worstCAGR: 0, moderateCAGR: 0, bestCAGR: 0 };

  const getLatest = (arr: DataPoint[]) => arr.length > 0 ? arr[arr.length - 1].value : 0;
  const baselineValue = getLatest(currentHistory);
  const getChange = (curr: number) => !baselineValue ? 0 : ((curr - baselineValue) / baselineValue) * 100;

  return (
    <div className="min-h-screen bg-slate-50 pb-20 font-sans text-slate-900">
      <header className="bg-white/80 backdrop-blur-md border-b border-slate-200 sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 h-14 flex items-center justify-between">
          <div className="flex items-center gap-3">
             <div className="w-7 h-7 bg-slate-900 rounded-lg flex items-center justify-center text-white font-black text-sm">7F</div>
             <h1 className="font-extrabold text-lg tracking-tight text-slate-900">Value-Up Quantum Simulator</h1>
          </div>
          <div className="flex items-center gap-4">
             <span className="hidden md:inline-block text-[10px] font-bold text-emerald-600 bg-emerald-50 px-2 py-1 rounded">AUGMENTED MODEL ACTIVE</span>
             <span className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">v4.0 Alpha</span>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 py-8">
        <ControlPanel config={config} setConfig={setConfig} onRunSimulation={handleManualRun} />

        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
          <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm relative group transition-all hover:shadow-md">
            <div className="absolute top-0 left-0 w-1.5 h-full bg-slate-200 group-hover:bg-slate-400 transition-colors"></div>
            <h3 className="text-[11px] font-black text-slate-400 uppercase tracking-widest mb-2">Value Trap (Worst)</h3>
            <div className="flex items-baseline gap-2 mb-3">
              <span className="text-3xl font-black text-slate-800 tracking-tighter">
                {safeAlt1.length > 0 ? Math.round(getLatest(safeAlt1)).toLocaleString() : '-'}
              </span>
              <span className={`text-sm font-bold ${getChange(getLatest(safeAlt1)) >= 0 ? 'text-emerald-500' : 'text-rose-500'}`}>
                {getChange(getLatest(safeAlt1)).toFixed(1)}%
              </span>
            </div>
             <div className="text-[10px] text-slate-500 font-medium">Implied CAGR: <span className="font-bold">{(safeMetrics.worstCAGR * 100).toFixed(1)}%</span></div>
          </div>

          <div className="bg-white p-6 rounded-xl border-2 border-indigo-100 shadow-lg relative group transition-all transform hover:-translate-y-1">
            <div className="absolute top-0 left-0 w-1.5 h-full bg-indigo-600"></div>
            <h3 className="text-[11px] font-black text-indigo-600 uppercase tracking-widest mb-2">Target Forecast (Moderate)</h3>
             <div className="flex items-baseline gap-2 mb-3">
              <span className="text-3xl font-black text-slate-900 tracking-tighter">
                {safeAlt2.length > 0 ? Math.round(getLatest(safeAlt2)).toLocaleString() : '-'}
              </span>
              <span className="text-sm font-bold text-emerald-600">
                +{getChange(getLatest(safeAlt2)).toFixed(1)}%
              </span>
            </div>
            <div className="flex items-center justify-between text-[10px] bg-indigo-50 text-indigo-700 p-2 rounded-lg font-bold">
                 <span>{config.modelType === 'FamaFrench5' ? '5-FACTOR' : '7-FACTOR'} SIGNAL:</span>
                 <span>{(safeMetrics.moderateCAGR * 100).toFixed(2)}% Ann.</span>
