// Error Boundary interfaces
interface ErrorBoundaryProps { 
  children?: ReactNode; 
}

interface ErrorBoundaryState { 
  hasError: boolean; 
}

/**
 * Standard React Error Boundary component.
 * Uses 'React.Component' to properly inherit state and props properties for TypeScript.
 */
// Using React.Component explicitly to resolve potential type inheritance issues in TypeScript
class ErrorBoundary extends React.Component<ErrorBoundaryProps, ErrorBoundaryState> {
  // Use class property initialization for state to avoid constructor-related type issues
  state: ErrorBoundaryState = { hasError: false };

  static getDerivedStateFromError(_: Error): ErrorBoundaryState { 
    return { hasError: true }; 
  }

  render() {
    // Accessing inherited state property from React.Component correctly
    if (this.state.hasError) {
      return <div className="p-10 text-center text-red-600 font-bold">CRITICAL ERROR: Please refresh simulation.</div>;
    }
    // Accessing inherited props property from React.Component correctly
    return this.props.children;
  }
}

