import React, { Component, useState, useEffect, useCallback, ReactNode } from 'react';
import { generateAllMarketData, runSimulation } from './services/dataService';
import SimulationChart from './components/SimulationChart';
import ControlPanel from './components/ControlPanel';
import { DataPoint, SimulationConfig, SimulationMetrics } from './types';

// Error Boundary interfaces
interface ErrorBoundaryProps { 
  children?: ReactNode; 
}

interface ErrorBoundaryState { 
  hasError: boolean; 
}

/**
 * Standard React Error Boundary component.
 * Uses 'Component' to properly inherit state and props properties for TypeScript.
 */
class ErrorBoundary extends Component<ErrorBoundaryProps, ErrorBoundaryState> {
  constructor(props: ErrorBoundaryProps) {
    super(props);
    this.state = { hasError: false };
  }

  static getDerivedStateFromError(_: Error): ErrorBoundaryState { 
    return { hasError: true }; 
  }

  render() {
    if (this.state.hasError) {
      return <div className="p-10 text-center text-red-600 font-bold">CRITICAL ERROR: Please refresh simulation.</div>;
    }
    return this.props.children;
  }
}

const AppContent = () => {
  const [loading, setLoading] = useState(true);
  const [datasets, setDatasets] = useState<any>(null);

  const [config, setConfig] = useState<SimulationConfig>({
    betaWeight: 1.0, 
    smbWeight: 0.1,  
    hmlWeight: 1.0,  
    rmwWeight: 1.0,  
    cmaWeight: 1.0,  
    qmjWeight: 1.0,  
    policyWeight: 0.5,
    volatility: 4,
    durationMonths: 60,
    referenceMarket: 'Japan',
    targetIndex: 'KOSPI',
    historyCutoffYear: 2025,
    modelType: 'FamaFrench5'
  });

  const [simResults, setSimResults] = useState<{
    targetIndex: string;
    alt1: DataPoint[];
    alt2: DataPoint[];
    alt3: DataPoint[];
    metrics?: SimulationMetrics;
  }>({ targetIndex: 'KOSPI', alt1: [], alt2: [], alt3: [] });

  useEffect(() => {
    const data = generateAllMarketData();
    setDatasets(data);
    setLoading(false);
  }, []);

  const runSim = useCallback((currentDatasets: any, currentConfig: SimulationConfig) => {
    if (!currentDatasets) return;
    const fullHistory: DataPoint[] = currentConfig.targetIndex === 'KOSPI' ? currentDatasets.kospiData : currentDatasets.kosdaqData;
    const effectiveHistory = fullHistory.filter((pt: DataPoint) => {
        const year = parseInt(pt.date.split('-')[0]);
        return year <= currentConfig.historyCutoffYear;
    });
    const results = runSimulation(effectiveHistory, currentConfig);
    setSimResults({
      targetIndex: currentConfig.targetIndex,
      alt1: results.alt1,
      alt2: results.alt2,
      alt3: results.alt3,
      metrics: results.metrics
    });
  }, []);

  const handleManualRun = () => runSim(datasets, config);

  useEffect(() => {
    if (datasets) runSim(datasets, config);
  }, [
      datasets, config.targetIndex, config.referenceMarket, config.historyCutoffYear, 
      config.modelType, config.betaWeight, config.smbWeight, config.hmlWeight, 
      config.rmwWeight, config.cmaWeight, config.qmjWeight, config.policyWeight
  ]); 

  if (loading || !datasets) return <div className="h-screen flex items-center justify-center text-indigo-600 font-bold animate-pulse">Initializing Engine...</div>;

  const fullHistory = config.targetIndex === 'KOSPI' ? datasets.kospiData : datasets.kosdaqData;
  const currentHistory = fullHistory.filter((pt: DataPoint) => parseInt(pt.date.split('-')[0]) <= config.historyCutoffYear);

  const currentReference = (() => {
    switch(config.referenceMarket) {
      case 'Japan': return datasets.japanData;
      case 'Taiwan': return datasets.taiwanData;
      case 'SP500': return datasets.sp500Data;
      case 'NASDAQ': return datasets.nasdaqData;
      case 'DowJones': return datasets.dowData;
      case 'Germany': return datasets.germanyData;
      default: return datasets.japanData;
    }
  })();

  const isDataSynced = simResults.targetIndex === config.targetIndex;
  const safeAlt1 = isDataSynced ? simResults.alt1 : [];
  const safeAlt2 = isDataSynced ? simResults.alt2 : [];
  const safeAlt3 = isDataSynced ? simResults.alt3 : [];
  const safeMetrics = isDataSynced && simResults.metrics ? simResults.metrics : { worstCAGR: 0, moderateCAGR: 0, bestCAGR: 0 };

  const getLatest = (arr: DataPoint[]) => arr.length > 0 ? arr[arr.length - 1].value : 0;
  const baselineValue = getLatest(currentHistory);
  const getChange = (curr: number) => !baselineValue ? 0 : ((curr - baselineValue) / baselineValue) * 100;

  return (
    <div className="min-h-screen bg-slate-50 pb-10 font-sans text-slate-900">
      <header className="bg-white/80 backdrop-blur-md border-b border-slate-200 sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 h-12 flex items-center justify-between">
          <div className="flex items-center gap-3">
             <div className="w-6 h-6 bg-slate-900 rounded flex items-center justify-center text-white font-black text-xs">VF</div>
             <h1 className="font-extrabold text-base tracking-tight text-slate-900">Value-Up Simulator</h1>
          </div>
          <div className="flex items-center gap-4">
             <span className="hidden md:inline-block text-[10px] font-bold text-emerald-600 bg-emerald-50 px-2 py-0.5 rounded border border-emerald-100">AUGMENTED ENGINE</span>
             <span className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">v4.2</span>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 py-4">
        <ControlPanel config={config} setConfig={setConfig} onRunSimulation={handleManualRun} />

        {/* 2. Key Scenario Indicators */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-4">
          <div className="bg-white py-3 px-5 rounded-xl border border-slate-200 shadow-sm relative group transition-all hover:shadow-md">
            <div className="absolute top-0 left-0 w-1 h-full bg-slate-200 group-hover:bg-slate-400 transition-colors"></div>
            <div className="flex justify-between items-start mb-0.5">
              <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Value Trap (Worst)</h3>
            </div>
            <p className="text-[8px] text-slate-400 leading-tight mb-2 font-medium">코리아 디스카운트 심화: 주주환원 인색 및 거버넌스 정체로 PBR 0.5 이하의 만성적 저평가가 지속되는 시나리오입니다.</p>
            <div className="flex items-baseline gap-2 mb-1">
              <span className="text-2xl font-black text-slate-800 tracking-tighter">
                {safeAlt1.length > 0 ? Math.round(getLatest(safeAlt1)).toLocaleString() : '-'}
              </span>
              <span className={`text-xs font-bold ${getChange(getLatest(safeAlt1)) >= 0 ? 'text-emerald-500' : 'text-rose-500'}`}>
                {getChange(getLatest(safeAlt1)).toFixed(1)}%
              </span>
            </div>
             <div className="text-[9px] text-slate-500 font-medium">CAGR: <span className="font-bold">{(safeMetrics.worstCAGR * 100).toFixed(1)}%</span></div>
          </div>

          <div className="bg-white py-3 px-5 rounded-xl border border-indigo-200 shadow-md relative group transition-all transform hover:-translate-y-0.5">
            <div className="absolute top-0 left-0 w-1 h-full bg-indigo-600"></div>
            <div className="flex justify-between items-start mb-0.5">
              <h3 className="text-[10px] font-black text-indigo-600 uppercase tracking-widest">Target Forecast (Moderate)</h3>
            </div>
            <p className="text-[8px] text-indigo-400 leading-tight mb-2 font-medium">밸류업 안착: 점진적 ROE 개선과 상장사 자율 공시 확대로 시장 평균 수준의 멀티플 리레이팅이 발생하는 경로입니다.</p>
             <div className="flex items-baseline gap-2 mb-1">
              <span className="text-2xl font-black text-slate-900 tracking-tighter">
                {safeAlt2.length > 0 ? Math.round(getLatest(safeAlt2)).toLocaleString() : '-'}
              </span>
              <span className="text-xs font-bold text-emerald-600">
                +{getChange(getLatest(safeAlt2)).toFixed(1)}%
              </span>
            </div>
            <div className="flex items-center justify-between text-[9px] bg-indigo-50 text-indigo-700 px-1.5 py-0.5 rounded font-bold">
                 <span>{config.modelType === 'FamaFrench5' ? '5-FACTOR' : '7-FACTOR'} SIGNAL:</span>
                 <span>{(safeMetrics.moderateCAGR * 100).toFixed(2)}% Ann.</span>
            </div>
          </div>

          <div className="bg-white py-3 px-5 rounded-xl border border-slate-200 shadow-sm relative group transition-all hover:shadow-md">
            <div className="absolute top-0 left-0 w-1 h-full bg-emerald-500 group-hover:bg-emerald-600 transition-colors"></div>
            <div className="flex justify-between items-start mb-0.5">
              <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Full Reform (Best)</h3>
            </div>
            <p className="text-[8px] text-emerald-400 leading-tight mb-2 font-medium">글로벌 스탠다드: 일본식 개혁 성공 사례를 따르며 코리아 디스카운트가 완전히 해소되고 선진국 지수에 부합하는 대세 상승장입니다.</p>
             <div className="flex items-baseline gap-2 mb-1">
              <span className="text-2xl font-black text-slate-800 tracking-tighter">
                {safeAlt3.length > 0 ? Math.round(getLatest(safeAlt3)).toLocaleString() : '-'}
              </span>
              <span className="text-xs font-bold text-emerald-600">
                +{getChange(getLatest(safeAlt3)).toFixed(1)}%
              </span>
            </div>
            <div className="text-[9px] text-slate-500 font-medium">CAGR: <span className="font-bold text-emerald-600">{(safeMetrics.bestCAGR * 100).toFixed(1)}%</span></div>
          </div>
        </div>

        <div className="bg-white p-3 rounded-2xl shadow-xl border border-slate-200 overflow-hidden">
          <SimulationChart 
            historyData={currentHistory} referenceData={currentReference}
            referenceMarket={config.referenceMarket} targetIndex={config.targetIndex}
            alt1Data={safeAlt1} alt2Data={safeAlt2} alt3Data={safeAlt3}
          />
        </div>
      </main>
    </div>
  );
};

