  };
};

// AI Engine Logic
const calculateLSTMNextStep = (prevVal: number, drift: number, volatility: number, momentum: number): { val: number, momentum: number } => {
    const noise = randomNormal(0, volatility);
    const newMomentum = (momentum * 0.75) + (drift * 0.25) + (noise * 0.15); 
    const step = newMomentum * prevVal;
    return { val: prevVal + step, momentum: newMomentum };
};

const calculateBoostingNextStep = (prevVal: number, drift: number, volatility: number): number => {
    const noise = randomNormal(0, volatility);
    let jump = 0;
    if (Math.random() > 0.90) jump = (Math.random() - 0.5) * volatility * 4.0;
    return prevVal * (1 + drift + noise + jump);
};

const calculateStandardNextStep = (prevVal: number, drift: number, volatility: number): number => {
    const noise = randomNormal(0, volatility);
    return prevVal * (1 + drift + noise);
};

export const runSimulation = (
  historyData: DataPoint[], 
  config: SimulationConfig
): { alt1: DataPoint[], alt2: DataPoint[], alt3: DataPoint[], metrics: SimulationMetrics } => {
  const alt1: DataPoint[] = []; 
  const alt2: DataPoint[] = []; 
  const alt3: DataPoint[] = []; 

  if (!historyData || historyData.length === 0) return { alt1, alt2, alt3, metrics: { worstCAGR: 0, moderateCAGR: 0, bestCAGR: 0 } };

  const lastPoint = historyData[historyData.length - 1];
  const startValue = lastPoint.value;
  const startDate = new Date(lastPoint.timestamp);
  const toWeeklyRate = (annualRate: number) => Math.pow(1 + annualRate, 1/52) - 1;

  let annualBaseGrowth = 0.08; 
  let volatilityRef = 0.04; 
  switch (config.referenceMarket) {
    case 'Japan': annualBaseGrowth = 0.10; volatilityRef = 0.04; break;
    case 'Taiwan': annualBaseGrowth = 0.12; volatilityRef = 0.055; break;
    case 'SP500': annualBaseGrowth = 0.11; volatilityRef = 0.035; break;
    case 'NASDAQ': annualBaseGrowth = 0.15; volatilityRef = 0.06; break;
    case 'DowJones': annualBaseGrowth = 0.09; volatilityRef = 0.03; break;
    case 'Germany': annualBaseGrowth = 0.085; volatilityRef = 0.04; break;
  }

  const RISK_FREE_RATE = 0.032;
  const SMB_PREMIUM = 0.025;
  const RMW_PREMIUM = 0.035;
  const CMA_PREMIUM = 0.028;
  const HML_PREMIUM = 0.032;
  const QMJ_PREMIUM = 0.045; 
  const POLICY_PREMIUM = 0.030; // Refers to P-Drive re-rating

  const marketPremium = annualBaseGrowth - RISK_FREE_RATE;
  const simVol = (volatilityRef / 2.0) * (config.volatility / 5.0);
  const totalWeeks = Math.floor(config.durationMonths * 4.345); 

  let val1 = startValue, val2 = startValue, val3 = startValue;
  let m1 = 0, m2 = 0, m3 = 0;

  const isFiveFactor = config.modelType === 'FamaFrench5';
  const effectiveQmjWeight = isFiveFactor ? 0 : config.qmjWeight;
  const effectivePolicyWeight = isFiveFactor ? 0 : config.policyWeight;

  // Annualised expected returns (Drifts)
  const worstAnn = RISK_FREE_RATE + (0.75 * marketPremium) - (0.3 * SMB_PREMIUM);
  const moderateAnn = RISK_FREE_RATE + (config.betaWeight * marketPremium) + (config.smbWeight * SMB_PREMIUM) + (config.hmlWeight * HML_PREMIUM) + (config.rmwWeight * RMW_PREMIUM) + (effectiveQmjWeight * QMJ_PREMIUM) + (effectivePolicyWeight * POLICY_PREMIUM);
  const bestAnn = moderateAnn + 0.025; // Re-rating alpha

  for (let i = 1; i <= totalWeeks; i++) {
    const newDate = new Date(startDate);
    newDate.setDate(startDate.getDate() + (i * 7));
    const dStr = formatDate(newDate); 
    const ts = newDate.getTime();

    // λ (Lambda): Time-varying policy credibility (starts low, grows to 1.0)
    const lambda = Math.min(1.0, 0.4 + (i / totalWeeks) * 0.6);

    // Dynamic Drift based on λ
    const d1 = toWeeklyRate(worstAnn);
    const d2 = toWeeklyRate(moderateAnn * (0.8 + 0.2 * lambda));
    const d3 = toWeeklyRate(bestAnn * (0.7 + 0.3 * lambda));

    if (config.modelType === 'LSTM' || config.modelType === 'GRU') {
        const r1 = calculateLSTMNextStep(val1, d1, simVol * 0.9, m1); val1 = r1.val; m1 = r1.momentum;
        const r2 = calculateLSTMNextStep(val2, d2, simVol * 0.9, m2); val2 = r2.val; m2 = r2.momentum;
        const r3 = calculateLSTMNextStep(val3, d3, simVol * 0.9, m3); val3 = r3.val; m3 = r3.momentum;
    } else if (config.modelType === 'XGBoost' || config.modelType === 'LightGBM') {
        val1 = calculateBoostingNextStep(val1, d1, simVol * 1.2);
        val2 = calculateBoostingNextStep(val2, d2, simVol * 1.2);
        val3 = calculateBoostingNextStep(val3, d3, simVol * 1.2);
    } else {
        val1 = calculateStandardNextStep(val1, d1, simVol);
        val2 = calculateStandardNextStep(val2, d2, simVol);
        val3 = calculateStandardNextStep(val3, d3, simVol);
    }

    alt1.push({ date: dStr, timestamp: ts, value: val1, type: 'Prediction', scenario: 'alt1_worst' });
    alt2.push({ date: dStr, timestamp: ts, value: val2, type: 'Prediction', scenario: 'alt2_moderate' });
    alt3.push({ date: dStr, timestamp: ts, value: val3, type: 'Prediction', scenario: 'alt3_best' });
  }

  return { 
    alt1, alt2, alt3, 
    metrics: { worstCAGR: worstAnn, moderateCAGR: moderateAnn, bestCAGR: bestAnn } 
  };
};

import React, { useMemo } from 'react';
import {
  LineChart,
  Line,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  Legend,
  ResponsiveContainer,
  ReferenceLine,
  ReferenceArea
} from 'recharts';
import { DataPoint, ReferenceMarket, TargetIndex } from '../types';

interface SimulationChartProps {
  historyData: DataPoint[];
  alt1Data: DataPoint[];
  alt2Data: DataPoint[];
  alt3Data: DataPoint[];
  referenceData: DataPoint[];
  referenceMarket: ReferenceMarket;
  targetIndex: TargetIndex;
}

const GenericLabel = (props: any) => {
  const { x, y, value, payload, index, stroke, isRef, actualRefVal, lastTimestamp, midTimestamp, periodicTimestamps } = props;
  if (x === undefined || y === undefined || !payload) return null;

  const dateStr = payload.date || "";
  const dateParts = dateStr.split('-');
  const year = parseInt(dateParts[0]);

  const isStart = index === 0;
  const isLast = payload.timestamp === lastTimestamp;
  const isMiddle = midTimestamp && payload.timestamp === midTimestamp;
  const isPeriodic = periodicTimestamps && periodicTimestamps.has(payload.timestamp);

  // 시작점, 끝점, 중간점, 혹은 지정된 주기(Periodic)에만 레이블 표시
  if (!isStart && !isLast && !isMiddle && !isPeriodic) return null;

  const valToShow = isRef ? (actualRefVal ?? value) : value;
  const displayVal = Math.round(valToShow).toLocaleString();

  const dyVal = isRef ? -28 : 32; 

  return (
    <g>
      <circle cx={x} cy={y} r={isStart || isLast ? 4 : 2.5} fill={stroke} stroke="#fff" strokeWidth={1.5} />
      <text x={x} y={y} dy={dyVal} stroke="#fff" strokeWidth={3} strokeLinecap="round" strokeLinejoin="round" fontSize={10} fontWeight="900" textAnchor="middle">{displayVal}</text>
      <text x={x} y={y} dy={dyVal} fill={stroke} fontSize={10} fontWeight="900" textAnchor="middle">{displayVal}</text>
      { (isLast || isStart || isPeriodic) && (
        <text x={x} y={y} dy={dyVal + (isRef ? -10 : 10)} fill="#94a3b8" fontSize={8} fontWeight="bold" textAnchor="middle">
          {isLast ? 'Now' : year}
        </text>
      )}
    </g>
  );
};

const ForecastLabel = (props: any) => {
  const { x, y, value, payload, stroke, lastTimestamp, orientation = 'top', periodicTimestamps, labelType } = props;
  if (x === undefined || y === undefined || !payload) return null;

  const isLast = payload.timestamp === lastTimestamp;
  const isPeriodic = periodicTimestamps && periodicTimestamps.has(payload.timestamp);

  if (!isLast && !isPeriodic) return null;

  const displayVal = Math.round(value).toLocaleString();

  let dyVal = 0;
  if (labelType === 'best') dyVal = -16;
  else if (labelType === 'moderate') dyVal = orientation === 'top' ? -14 : 24;
  else if (labelType === 'worst') dyVal = 28;

  return (
    <g>
      <circle cx={x} cy={y} r={isLast ? 3.5 : 2} fill={stroke} stroke="#fff" strokeWidth={1} />
      <rect x={x - 20} y={y + dyVal - 9} width={40} height={12} rx={2} fill="white" stroke={stroke} strokeWidth={0.5} opacity={0.8} />
      <text x={x} y={y + dyVal} fill={stroke} fontSize={8} fontWeight="900" textAnchor="middle" alignmentBaseline="middle">{displayVal}</text>
      {isLast && (
        <text x={x} y={y + dyVal + (dyVal < 0 ? -10 : 16)} fill={stroke} fontSize={7} fontWeight="black" textAnchor="middle">
          {labelType?.toUpperCase()}
        </text>
      )}
    </g>
  );
};

const SimulationChart: React.FC<SimulationChartProps> = ({
  historyData, alt1Data, alt2Data, alt3Data, referenceData, referenceMarket, targetIndex
}) => {
  const lastHistoryTs = historyData.length > 0 ? historyData[historyData.length - 1].timestamp : 0;
  const lastRefTs = referenceData.length > 0 ? referenceData[referenceData.length - 1].timestamp : 0;
  const lastForecastTs = alt1Data.length > 0 ? alt1Data[alt1Data.length - 1].timestamp : 0;
  const midHistoryTs = historyData.length > 0 ? historyData[Math.floor(historyData.length / 2)].timestamp : 0;

  const chartData = useMemo(() => {
    const dataMap = new Map<number, any>();
    const process = (data: DataPoint[], key: string, isRef = false) => {
      data.forEach(pt => {
        if (!dataMap.has(pt.timestamp)) {
          dataMap.set(pt.timestamp, { date: pt.date, timestamp: pt.timestamp });
        }
        const entry = dataMap.get(pt.timestamp);
        if (isRef) entry[`reference_actual`] = pt.value;
        else entry[key] = pt.value;
      });
    };
    process(referenceData, 'reference', true);
    process(historyData, 'history');
    process(alt1Data, 'alt1');
    process(alt2Data, 'alt2');
    process(alt3Data, 'alt3');
    return Array.from(dataMap.values()).sort((a, b) => a.timestamp - b.timestamp);
  }, [referenceData, historyData, alt1Data, alt2Data, alt3Data]);

  // X축 간격을 균등하게 만들기 위해 도메인과 틱을 명시적으로 계산
  const { domain, ticks } = useMemo(() => {
    if (chartData.length === 0) return { domain: [0, 0], ticks: [] };

    const startYear = new Date(chartData[0].timestamp).getFullYear();
    const endYear = new Date(chartData[chartData.length - 1].timestamp).getFullYear();

    // 도메인을 연초(1월 1일)부터 연말까지로 설정하여 연도별 픽셀 간격 균등화
    const minDomain = new Date(startYear, 0, 1).getTime();
    const maxDomain = new Date(endYear, 11, 31).getTime();

    const generatedTicks = [];
    // 3년 단위로 틱 생성 (가독성과 균등 간격 유지)
    for (let year = startYear; year <= endYear; year++) {
      if ((year - startYear) % 3 === 0 || year === endYear) {
        generatedTicks.push(new Date(year, 0, 1).getTime());
      }
    }

    return { domain: [minDomain, maxDomain], ticks: generatedTicks };
  }, [chartData]);

  const referencePeriodicTimestamps = useMemo(() => {
    const set = new Set<number>();
    const seenYears = new Set<number>();
    if (referenceData && referenceData.length > 0) {
      referenceData.forEach(d => {
        const parts = d.date.split('-');
        const year = parseInt(parts[0]);
        const month = parseInt(parts[1]);
        if (month === 1 && year % 3 === 0 && !seenYears.has(year)) {
          seenYears.add(year);
          set.add(d.timestamp);
        }
      });
    }
    return set;
  }, [referenceData]);

  const forecastPeriodicTimestamps = useMemo(() => {
    const set = new Set<number>();
    const seenYears = new Set<number>();
    if (alt1Data && alt1Data.length > 0) {
      alt1Data.forEach(d => {
        const parts = d.date.split('-');
        const year = parseInt(parts[0]);
        const month = parseInt(parts[1]);
        if (month === 6 && !seenYears.has(year)) {
          seenYears.add(year);
          set.add(d.timestamp);
        }
      });
    }
    return set;
  }, [alt1Data]);

  const CustomTooltip = ({ active, payload, label }: any) => {
    if (active && payload && payload.length) {
      const date = new Date(label).toLocaleDateString('en-US', { year: 'numeric', month: 'short' });
      return (
        <div className="bg-white/95 border border-slate-200 p-3 rounded shadow-xl text-xs backdrop-blur-sm z-50">
          <p className="font-bold border-b border-slate-100 pb-1 mb-2 text-slate-800">{date}</p>
          {payload.map((entry: any, i: number) => (
            <div key={i} className="flex items-center justify-between gap-4 mb-1">
              <span className="flex items-center gap-2 text-slate-600">
                <span className="w-2 h-2 rounded-full" style={{ background: entry.color }}></span>
                {entry.dataKey === 'reference_actual' ? referenceMarket : entry.name}:
              </span>
              <span className="font-mono font-bold text-slate-800">{Math.round(entry.value).toLocaleString()}</span>
            </div>
          ))}
        </div>
      );
    }
    return null;
  };

  return (
    <div className="bg-white p-2 md:p-4 rounded-xl border border-slate-200 shadow-sm h-[520px]">
      <ResponsiveContainer width="100%" height="100%">
        <LineChart data={chartData} margin={{ top: 40, right: 40, left: 15, bottom: 20 }}>
          <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
          <XAxis 
            dataKey="timestamp" 
            type="number"
            scale="time"
            domain={domain}
            ticks={ticks}
            tickFormatter={(ts) => new Date(ts).getFullYear().toString()} 
            tick={{ fontSize: 10, fill: '#94a3b8' }} 
          />
          <YAxis 
            yAxisId="left" 
            domain={['auto', 'auto']} 
            tick={{ fontSize: 10, fill: '#0f172a', fontWeight: 600 }} 
            width={55}
            label={{ value: targetIndex, angle: -90, position: 'insideLeft', offset: 0, fill: '#0f172a', fontSize: 11, fontWeight: 900 }}
          />
          <YAxis 
            yAxisId="right" 
            orientation="right" 
            domain={['auto', 'auto']} 
            tick={{ fontSize: 10, fill: '#94a3b8' }} 
            width={55}
            label={{ value: referenceMarket, angle: 90, position: 'insideRight', offset: 0, fill: '#94a3b8', fontSize: 11, fontWeight: 900 }}
          />
          <Tooltip content={<CustomTooltip />} />
          <Legend wrapperStyle={{ paddingTop: '15px', fontSize: '11px' }} />

          <Line yAxisId="right" type="monotone" dataKey="reference_actual" name={`${referenceMarket} (Ref)`} stroke="#cbd5e1" strokeWidth={1.5} strokeDasharray="3 3" dot={false} connectNulls label={(p) => <GenericLabel {...p} stroke="#94a3b8" isRef={true} lastTimestamp={lastRefTs} periodicTimestamps={referencePeriodicTimestamps} />} />
          <Line yAxisId="left" type="monotone" dataKey="history" name={`${targetIndex} History`} stroke="#0f172a" strokeWidth={2} dot={false} connectNulls label={(p) => <GenericLabel {...p} stroke="#0f172a" isRef={false} lastTimestamp={lastHistoryTs} midTimestamp={midHistoryTs} />} />

          <Line yAxisId="left" type="monotone" dataKey="alt1" name="Worst" stroke="#ef4444" strokeWidth={1.5} strokeDasharray="4 4" dot={false} label={(p) => <ForecastLabel {...p} stroke="#ef4444" lastTimestamp={lastForecastTs} orientation="bottom" labelType="worst" periodicTimestamps={forecastPeriodicTimestamps} />} />
          <Line yAxisId="left" type="monotone" dataKey="alt2" name="Moderate" stroke="#3b82f6" strokeWidth={2} dot={false} label={(p) => <ForecastLabel {...p} stroke="#3b82f6" lastTimestamp={lastForecastTs} orientation="top" labelType="moderate" periodicTimestamps={forecastPeriodicTimestamps} />} />
          <Line yAxisId="left" type="monotone" dataKey="alt3" name="Best" stroke="#22c55e" strokeWidth={2} dot={false} label={(p) => <ForecastLabel {...p} stroke="#22c55e" lastTimestamp={lastForecastTs} orientation="top" labelType="best" periodicTimestamps={forecastPeriodicTimestamps} />} />

          {alt1Data.length > 0 && (
             <ReferenceArea yAxisId="left" x1={alt1Data[0].timestamp} x2={alt1Data[alt1Data.length - 1].timestamp} fill="#f8fafc" fillOpacity={0.4} label={{ value: "FORECAST", position: "insideTopLeft", fill: "#94a3b8", fontSize: 10, fontWeight: 800, dy: 10, dx: 10 }} />
          )}
          {alt1Data.length > 0 && <ReferenceLine yAxisId="left" x={alt1Data[0].timestamp} stroke="#cbd5e1" strokeDasharray="3 3" />}
        </LineChart>
      </ResponsiveContainer>
    </div>
  );
};

