import React, { useMemo } from 'react';
import { DataPoint, ReferenceMarket, TargetIndex } from '../types';

interface DataTableProps {
  historyData: DataPoint[];
  referenceData: DataPoint[];
  referenceMarket: ReferenceMarket;
  targetIndex: TargetIndex;
  alt1Data: DataPoint[];
  alt2Data: DataPoint[];
  alt3Data: DataPoint[];
}

const DataTable: React.FC<DataTableProps> = ({ 
  historyData, 
  referenceData, 
  referenceMarket, 
  targetIndex,
  alt1Data, 
  alt2Data, 
  alt3Data 
}) => {
  const tableData = useMemo(() => {
    const milestones: any[] = [];

    // 역사적 데이터 선별 (3년 주기 + 주요 지점)
    const historyYears = [2010, 2013, 2016, 2019, 2022, 2024];
    historyYears.forEach(year => {
      const targetPoint = historyData.find(d => d.date.startsWith(`${year}-12`)) || 
                          historyData.find(d => d.date.startsWith(`${year}`));
      const refPoint = referenceData.find(d => d.date.startsWith(`${year}-12`)) || 
                       referenceData.find(d => d.date.startsWith(`${year}`));

      if (targetPoint) {
        milestones.push({
          date: `${year} Year-end`,
          reference: refPoint ? refPoint.value : null,
          history: targetPoint.value,
          worst: null,
          moderate: null,
          best: null,
          isHistory: true
        });
      }
    });

    // 현재 시점 (Baseline)
    if (historyData.length > 0) {
      const last = historyData[historyData.length - 1];
      const lastRef = referenceData.find(d => d.timestamp === last.timestamp) || referenceData[referenceData.length - 1];
      milestones.push({
        date: '2025-06 (Base)',
        reference: lastRef ? lastRef.value : null,
        history: last.value,
        worst: last.value,
        moderate: last.value,
        best: last.value,
        isBase: true
      });
    }

    // 전망 데이터 선별 (분기별: 3, 6, 9, 12월)
    const forecastYears = [2026, 2027, 2028, 2029, 2030];
    const quarters = ['03', '06', '09', '12'];

    forecastYears.forEach(year => {
      quarters.forEach(q => {
        const prefix = `${year}-${q}`;
        const idx1 = alt1Data.find(d => d.date.startsWith(prefix));
        const idx2 = alt2Data.find(d => d.date.startsWith(prefix));
        const idx3 = alt3Data.find(d => d.date.startsWith(prefix));

        if (idx1 && idx2 && idx3) {
          milestones.push({
            date: prefix,
            reference: null,
            history: null,
            worst: idx1.value,
            moderate: idx2.value,
            best: idx3.value,
            isForecast: true
          });
        }
      });
    });

    return milestones;
  }, [historyData, referenceData, alt1Data, alt2Data, alt3Data]);

  return (
    <div className="mt-6 bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
      <div className="bg-slate-50 px-5 py-3 border-b border-slate-200 flex justify-between items-center">
        <h3 className="text-[11px] font-black text-slate-800 uppercase tracking-widest flex items-center gap-2">
          <svg className="w-3 h-3 text-indigo-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M4 6h16M4 10h16M4 14h16M4 18h16"></path></svg>
          Key Milestone Data Points (Historical & Quarterly Forecast)
        </h3>
        <span className="text-[9px] font-bold text-slate-400">Values rounded to nearest integer</span>
      </div>
      <div className="overflow-x-auto">
        <table className="w-full text-left border-collapse min-w-[700px]">
          <thead>
            <tr className="bg-white border-b border-slate-100">
              <th className="px-5 py-3 text-[10px] font-black text-slate-400 uppercase tracking-wider">Timeline</th>
              <th className="px-5 py-3 text-[10px] font-black text-slate-500 uppercase tracking-wider bg-slate-50/20 italic">{referenceMarket}</th>
              <th className="px-5 py-3 text-[10px] font-black text-slate-900 uppercase tracking-wider bg-slate-50/50">Historical ({targetIndex})</th>
              <th className="px-5 py-3 text-[10px] font-black text-rose-500 uppercase tracking-wider">Worst (Trap)</th>
              <th className="px-5 py-3 text-[10px] font-black text-indigo-600 uppercase tracking-wider">Moderate (Base)</th>
              <th className="px-5 py-3 text-[10px] font-black text-emerald-600 uppercase tracking-wider">Best (Target)</th>
            </tr>
          </thead>
          <tbody>
            {tableData.map((row, idx) => (
              <tr key={idx} className={`border-b border-slate-50 transition-colors hover:bg-slate-50/30 ${row.isBase ? 'bg-indigo-50/30' : ''}`}>
                <td className="px-5 py-2.5">
                  <span className={`text-[11px] font-bold ${row.isForecast ? 'text-indigo-600' : 'text-slate-600'}`}>
                    {row.date}
                  </span>
                </td>
                <td className="px-5 py-2.5 font-mono text-[11px] text-slate-400 italic">
                  {row.reference ? Math.round(row.reference).toLocaleString() : '-'}
                </td>
                <td className="px-5 py-2.5 bg-slate-50/30 font-mono text-[11px] font-bold text-slate-900">
                  {row.history ? Math.round(row.history).toLocaleString() : '-'}
                </td>
                <td className="px-5 py-2.5 font-mono text-[11px] font-bold text-rose-500">
                  {row.worst ? Math.round(row.worst).toLocaleString() : '-'}
                </td>
                <td className="px-5 py-2.5 font-mono text-[11px] font-bold text-indigo-700">
                  {row.moderate ? Math.round(row.moderate).toLocaleString() : '-'}
                </td>
                <td className="px-5 py-2.5 font-mono text-[11px] font-bold text-emerald-600">
                  {row.best ? Math.round(row.best).toLocaleString() : '-'}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
      <div className="bg-slate-50 px-5 py-2 border-t border-slate-100">
        <p className="text-[9px] text-slate-400 font-medium italic">
          * Historical 섹션은 실제 지수 데이터를, Forecast 섹션은 분기별 기댓값을 나타냅니다. 
        </p>
      </div>
    </div>
  );
};

export default DataTable;

import React from 'react';
import {
  LineChart,
  Line,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  ResponsiveContainer,
  LabelList
} from 'recharts';

interface MilestoneChartProps {
  data: any[];
  targetIndex: string;
}

const CustomizedLabel = (props: any) => {
  const { x, y, value, index, dataLength } = props;
  // 시작, 베이스(현재), 마지막 포인트만 레이블 표시
  const isSpecial = index === 0 || index === dataLength - 1 || value > 4000; // 혹은 특정 조건

  if (index % 4 !== 0 && index !== dataLength - 1) return null;

  return (
    <text x={x} y={y} dy={-10} fill={props.stroke} fontSize={9} fontWeight="bold" textAnchor="middle">
      {Math.round(value).toLocaleString()}
    </text>
  );
};

const MilestoneChart: React.FC<MilestoneChartProps> = ({ data, targetIndex }) => {
  // 표 데이터 중 유효한 값들만 필터링 (그래프용)
  const chartData = data.map(d => ({
    ...d,
    // 그래프 연결을 위해 null 값 처리 (history -> forecast 연결)
    displayWorst: d.worst || d.history,
    displayModerate: d.moderate || d.history,
    displayBest: d.best || d.history,
  }));

  return (
    <div className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm h-[350px] mt-6">
      <div className="flex justify-between items-center mb-4">
        <h3 className="text-[11px] font-black text-slate-800 uppercase tracking-widest flex items-center gap-2">
          <svg className="w-3 h-3 text-indigo-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M7 12l3-3 3 3 4-4M8 21l4-4 4 4M3 4h18M4 4h16v12a1 1 0 01-1 1H5a1 1 0 01-1-1V4z"></path></svg>
          Milestone Trend Summary (Closing Prices)
        </h3>
      </div>
      <ResponsiveContainer width="100%" height="100%">
        <LineChart data={chartData} margin={{ top: 20, right: 30, left: 10, bottom: 20 }}>
          <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
          <XAxis 
            dataKey="date" 
            tick={{ fontSize: 9, fill: '#94a3b8', fontWeight: 'bold' }}
            interval="preserveStartEnd"
          />
          <YAxis 
            hide
            domain={['auto', 'auto']}
          />
          <Tooltip 
            contentStyle={{ fontSize: '10px', borderRadius: '8px', border: 'none', boxShadow: '0 10px 15px -3px rgba(0,0,0,0.1)' }}
            formatter={(value: any) => [Math.round(value).toLocaleString(), 'Closing Price']}
          />

          <Line 
            type="monotone" 
            dataKey="history" 
            name="History" 
            stroke="#0f172a" 
            strokeWidth={3} 
            dot={{ r: 3, fill: '#0f172a' }}
            connectNulls
          >
             <LabelList dataKey="history" content={<CustomizedLabel dataLength={chartData.length} />} />
          </Line>

          <Line 
            type="monotone" 
            dataKey="displayWorst" 
            name="Worst" 
            stroke="#ef4444" 
            strokeWidth={2} 
            strokeDasharray="5 5"
            dot={{ r: 2 }}
          />

          <Line 
            type="monotone" 
            dataKey="displayModerate" 
            name="Moderate" 
            stroke="#3b82f6" 
            strokeWidth={2} 
            dot={{ r: 2 }}
          >
             <LabelList dataKey="displayModerate" content={<CustomizedLabel dataLength={chartData.length} />} />
          </Line>

          <Line 
            type="monotone" 
            dataKey="displayBest" 
            name="Best" 
            stroke="#22c55e" 
            strokeWidth={2} 
            dot={{ r: 2 }}
          >
             <LabelList dataKey="displayBest" content={<CustomizedLabel dataLength={chartData.length} />} />
          </Line>
        </LineChart>
      </ResponsiveContainer>
    </div>
  );
};

