        const prefix = `${year}-${q}`;
        const idx1 = safeAlt1.find(d => d.date.startsWith(prefix));
        const idx2 = safeAlt2.find(d => d.date.startsWith(prefix));
        const idx3 = safeAlt3.find(d => d.date.startsWith(prefix));
        if (idx1 && idx2 && idx3) {
          milestones.push({
            date: prefix,
            reference: null,
            history: null,
            worst: idx1.value,
            moderate: idx2.value,
            best: idx3.value,
            isForecast: true
          });
        }
      });
    });
    return milestones;
  }, [currentHistory, currentReference, safeAlt1, safeAlt2, safeAlt3]);

  const getLatest = (arr: DataPoint[]) => arr.length > 0 ? arr[arr.length - 1].value : 0;
