const CustomizedLabel = (props: any) => {
  const { x, y, value, index, dataLength, stroke } = props;

  // 데이터가 없거나 인덱스가 비정상적일 경우 렌더링 안함
  if (value === null || value === undefined || isNaN(value)) return null;
  if (index === undefined || dataLength === undefined) return null;

  // 특정 포인트(시작, 베이스, 마지막 등)에만 레이블 표시
  if (index % 4 !== 0 && index !== dataLength - 1) return null;

  return (
    <text 
      x={x} 
      y={y} 
      dy={-10} 
      fill={stroke || "#333"} 
      fontSize={9} 
      fontWeight="bold" 
      textAnchor="middle"
    >
      {Math.round(value).toLocaleString()}
    </text>
  );
};

const MilestoneChart: React.FC<MilestoneChartProps> = ({ data, targetIndex }) => {
  if (!data || data.length === 0) return null;

  const chartData = data.map(d => ({
    ...d,
    displayWorst: d.worst !== null ? d.worst : d.history,
    displayModerate: d.moderate !== null ? d.moderate : d.history,
    displayBest: d.best !== null ? d.best : d.history,
