interface ErrorBoundaryProps { 
  children?: ReactNode; 
}

interface ErrorBoundaryState { 
  hasError: boolean; 
}

class ErrorBoundary extends Component<ErrorBoundaryProps, ErrorBoundaryState> {
  constructor(props: ErrorBoundaryProps) {
    super(props);
    this.state = { hasError: false };
  }

  static getDerivedStateFromError(_: Error): ErrorBoundaryState { 
    return { hasError: true }; 
  }

  render() {
    if (this.state.hasError) {
      return (
        <div className="p-10 text-center">
          <div className="bg-red-50 border border-red-200 p-6 rounded-2xl inline-block">
            <h2 className="text-red-600 font-black mb-2">SIMULATION ENGINE ERROR</h2>
            <p className="text-red-400 text-sm mb-4">데이터 처리 중 오류가 발생했습니다. 설정을 초기화하거나 페이지를 새로고침 해주세요.</p>
            <button 
              onClick={() => window.location.reload()}
              className="bg-red-600 text-white px-4 py-2 rounded-lg font-bold text-xs"
            >
              RELOAD ENGINE
            </button>
          </div>
        </div>
      );
    }
    return this.props.children;
  }
}

const AppContent = () => {
  const [loading, setLoading] = useState(true);
  const [datasets, setDatasets] = useState<any>(null);

  const [config, setConfig] = useState<SimulationConfig>({
    betaWeight: 1.0, 
    smbWeight: 0.1,  
    hmlWeight: 1.0,  
    rmwWeight: 1.2,  
    cmaWeight: 1.0,  
    qmjWeight: 1.2,  
