const renderCustomizedLabel = (props: any) => {
  const { x, y, value, index, stroke } = props;

  // props 검증
  if (value === null || value === undefined || isNaN(value)) return null;

  // 특정 포인트(대략 4분기마다 하나씩 + 마지막 점)에만 레이블 표시
  // milestoneData는 역사적 데이터(YE) + 분기별 데이터로 구성됨
  // 인덱스 기반으로 적절히 분배하여 표시
  const shouldShow = index === 0 || index % 4 === 0;

  if (!shouldShow) return null;

  return (
    <text 
      x={x} 
      y={y} 
      dy={-10} 
      fill={stroke || "#333"} 
      fontSize={9} 
      fontWeight="bold" 
      textAnchor="middle"
    >
      {Math.round(value).toLocaleString()}
    </text>
  );
};

const MilestoneChart: React.FC<MilestoneChartProps> = ({ data, targetIndex }) => {
  if (!data || data.length === 0) return null;

  // Forecast 데이터 연결을 위한 가공
  const chartData = data.map(d => ({
    ...d,
    displayWorst: d.worst !== null ? d.worst : d.history,
