import React from 'react';
import {
  LineChart,
  Line,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  ResponsiveContainer,
  LabelList
} from 'recharts';

interface MilestoneChartProps {
  data: any[];
  targetIndex: string;
}

/**
 * 커스텀 레이블 렌더러
 * 데이터 포인트 위에 종가를 표시합니다.
 */
const renderCustomizedLabel = (props: any) => {
  const { x, y, value, index, stroke } = props;

  // 유효성 검사: 수치가 없거나 숫자가 아닌 경우 렌더링 안함
  if (value === null || value === undefined || isNaN(Number(value))) return null;

  // 전체 시계열이 아닌 주요 마일스톤(시작점, 4분기 간격, 끝점)만 레이블 표시
  // milestoneData 구조에 따라 인덱스 기반 필터링
  const shouldShow = index === 0 || index % 4 === 0;

  if (!shouldShow) return null;

  return (
    <text 
      x={x} 
      y={y} 
      dy={-10} 
      fill={stroke || "#475569"} 
      fontSize={9} 
      fontWeight="700" 
      textAnchor="middle"
      style={{ pointerEvents: 'none' }}
    >
      {Math.round(Number(value)).toLocaleString()}
    </text>
  );
};

const MilestoneChart: React.FC<MilestoneChartProps> = ({ data, targetIndex }) => {
  // 데이터가 없거나 형식이 잘못된 경우 렌더링 방어
  if (!data || !Array.isArray(data) || data.length === 0) {
    return null;
  }

  // 예측 데이터 시각화를 위해 연결점(Base) 데이터 가공
  const chartData = data.map(d => ({
    ...d,
    displayWorst: d.worst !== null ? d.worst : (d.isBase ? d.history : null),
    displayModerate: d.moderate !== null ? d.moderate : (d.isBase ? d.history : null),
    displayBest: d.best !== null ? d.best : (d.isBase ? d.history : null),
  }));

  return (
    <div className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm h-[350px] mt-6">
      <div className="flex justify-between items-center mb-4">
        <h3 className="text-[11px] font-black text-slate-800 uppercase tracking-widest flex items-center gap-2">
          <svg className="w-3.5 h-3.5 text-indigo-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M7 12l3-3 3 3 4-4M8 21l4-4 4 4M3 4h18M4 4h16v12a1 1 0 01-1 1H5a1 1 0 01-1-1V4z"></path>
          </svg>
          Milestone Trend Summary (Closing Prices)
        </h3>
        <div className="flex items-center gap-3">
          <span className="flex items-center gap-1 text-[9px] font-bold text-slate-400">
            <span className="w-2 h-0.5 bg-slate-900"></span> History
          </span>
          <span className="flex items-center gap-1 text-[9px] font-bold text-indigo-600">
            <span className="w-2 h-0.5 bg-indigo-600"></span> Forecast
          </span>
        </div>
      </div>
      <ResponsiveContainer width="100%" height="100%">
        <LineChart data={chartData} margin={{ top: 25, right: 30, left: 10, bottom: 20 }}>
          <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
          <XAxis 
            dataKey="date" 
            tick={{ fontSize: 9, fill: '#94a3b8', fontWeight: 'bold' }}
            interval="preserveStartEnd"
            axisLine={{ stroke: '#e2e8f0' }}
            tickLine={false}
          />
          <YAxis 
            hide
            domain={['auto', 'auto']}
          />
          <Tooltip 
            contentStyle={{ 
              fontSize: '10px', 
              borderRadius: '8px', 
              border: 'none', 
              boxShadow: '0 10px 15px -3px rgba(0,0,0,0.1)',
              backgroundColor: 'rgba(255, 255, 255, 0.95)'
            }}
            formatter={(value: any) => [Math.round(Number(value)).toLocaleString(), 'Closing Price']}
          />

          {/* 역사적 데이터 라인 */}
          <Line 
            type="monotone" 
            dataKey="history" 
            name="History" 
            stroke="#0f172a" 
            strokeWidth={3} 
            dot={{ r: 3, fill: '#0f172a', strokeWidth: 2, stroke: '#fff' }}
            connectNulls
            activeDot={{ r: 5 }}
          >
             <LabelList dataKey="history" content={renderCustomizedLabel} />
          </Line>

          {/* Worst 시나리오 라인 */}
          <Line 
            type="monotone" 
            dataKey="displayWorst" 
            name="Worst" 
            stroke="#ef4444" 
            strokeWidth={2} 
            strokeDasharray="5 5"
            dot={false}
            connectNulls
          />

          {/* Moderate 시나리오 라인 */}
          <Line 
            type="monotone" 
            dataKey="displayModerate" 
            name="Moderate" 
            stroke="#3b82f6" 
            strokeWidth={2} 
            dot={{ r: 2, fill: '#3b82f6' }}
            connectNulls
          >
             <LabelList dataKey="displayModerate" content={renderCustomizedLabel} />
          </Line>

          {/* Best 시나리오 라인 */}
          <Line 
            type="monotone" 
            dataKey="displayBest" 
            name="Best" 
            stroke="#22c55e" 
            strokeWidth={2} 
            dot={{ r: 2, fill: '#22c55e' }}
            connectNulls
          >
             <LabelList dataKey="displayBest" content={renderCustomizedLabel} />
          </Line>
        </LineChart>
      </ResponsiveContainer>
    </div>
  );
};

export default MilestoneChart;

import React, { Component, useState, useEffect, useCallback, ReactNode, useMemo } from 'react';
import { generateAllMarketData, runSimulation } from './services/dataService';
import SimulationChart from './components/SimulationChart';
import ControlPanel from './components/ControlPanel';
import DataTable from './components/DataTable';
import MilestoneChart from './components/MilestoneChart';
import { DataPoint, SimulationConfig, SimulationMetrics } from './types';

interface ErrorBoundaryProps { 
  children?: ReactNode; 
}

interface ErrorBoundaryState { 
  hasError: boolean; 
}

class ErrorBoundary extends Component<ErrorBoundaryProps, ErrorBoundaryState> {
  constructor(props: ErrorBoundaryProps) {
    super(props);
    this.state = { hasError: false };
  }

  static getDerivedStateFromError(_: Error): ErrorBoundaryState { 
    return { hasError: true }; 
  }

  render() {
    if (this.state.hasError) {
      return (
        <div className="p-10 text-center">
          <div className="bg-red-50 border border-red-200 p-6 rounded-2xl inline-block shadow-lg">
            <h2 className="text-red-600 font-black mb-2">SIMULATION ENGINE HALTED</h2>
            <p className="text-red-400 text-sm mb-4">런타임 오류가 발생했습니다. 라이브러리 충돌이 의심되오니 페이지를 새로고침 해주세요.</p>
            <button 
              onClick={() => window.location.reload()}
              className="bg-red-600 hover:bg-red-700 text-white px-6 py-2.5 rounded-lg font-bold text-xs transition-colors"
            >
              FORCE RELOAD ENGINE
            </button>
          </div>
        </div>
      );
    }
    return this.props.children;
  }
}

const AppContent = () => {
  const [loading, setLoading] = useState(true);
  const [datasets, setDatasets] = useState<any>(null);

  const [config, setConfig] = useState<SimulationConfig>({
    betaWeight: 1.0, 
    smbWeight: 0.1,  
    hmlWeight: 1.0,  
    rmwWeight: 1.2,  
    cmaWeight: 1.0,  
    qmjWeight: 1.2,  
    policyWeight: 0.7,
    volatility: 4,
    durationMonths: 66, 
    referenceMarket: 'Japan',
    targetIndex: 'KOSPI',
    historyCutoffYear: 2025,
    modelType: 'FamaFrench' 
  });

  const [simResults, setSimResults] = useState<{
    targetIndex: string;
    alt1: DataPoint[];
    alt2: DataPoint[];
    alt3: DataPoint[];
    metrics?: SimulationMetrics;
  }>({ targetIndex: 'KOSPI', alt1: [], alt2: [], alt3: [] });

  useEffect(() => {
    try {
      const data = generateAllMarketData();
      setDatasets(data);
      setLoading(false);
    } catch (e) {
      console.error("Data generation failed", e);
    }
  }, []);

  const runSim = useCallback((currentDatasets: any, currentConfig: SimulationConfig) => {
    if (!currentDatasets) return;
    try {
      const fullHistory: DataPoint[] = currentConfig.targetIndex === 'KOSPI' ? currentDatasets.kospiData : currentDatasets.kosdaqData;
      const effectiveHistory = fullHistory.filter((pt: DataPoint) => {
          const year = parseInt(pt.date.split('-')[0]);
          return year <= currentConfig.historyCutoffYear;
      });
      const results = runSimulation(effectiveHistory, currentConfig);
      setSimResults({
        targetIndex: currentConfig.targetIndex,
        alt1: results.alt1,
        alt2: results.alt2,
        alt3: results.alt3,
        metrics: results.metrics
      });
    } catch (e) {
      console.error("Simulation failed", e);
    }
  }, []);

  const handleManualRun = () => runSim(datasets, config);

  useEffect(() => {
    if (datasets) runSim(datasets, config);
  }, [
      datasets, config.targetIndex, config.referenceMarket, config.historyCutoffYear, 
      config.modelType, config.betaWeight, config.smbWeight, config.hmlWeight, 
      config.rmwWeight, config.cmaWeight, config.qmjWeight, config.policyWeight,
      config.durationMonths, runSim
  ]); 

  if (loading || !datasets) return <div className="h-screen flex items-center justify-center text-indigo-600 font-bold animate-pulse">Initializing Value-Up Engine...</div>;

  const fullHistory = config.targetIndex === 'KOSPI' ? datasets.kospiData : datasets.kosdaqData;
  const currentHistory = fullHistory.filter((pt: DataPoint) => parseInt(pt.date.split('-')[0]) <= config.historyCutoffYear);

  const currentReference = (() => {
    const market = config.referenceMarket;
    if (market === 'Japan') return datasets.japanData;
    if (market === 'Taiwan') return datasets.taiwanData;
    if (market === 'SP500') return datasets.sp500Data;
    if (market === 'NASDAQ') return datasets.nasdaqData;
    if (market === 'DowJones') return datasets.dowData;
    if (market === 'Germany') return datasets.germanyData;
    return datasets.japanData;
  })();

  const isDataSynced = simResults.targetIndex === config.targetIndex;
  const safeAlt1 = isDataSynced ? simResults.alt1 : [];
  const safeAlt2 = isDataSynced ? simResults.alt2 : [];
  const safeAlt3 = isDataSynced ? simResults.alt3 : [];
  const safeMetrics = isDataSynced && simResults.metrics ? simResults.metrics : { worstCAGR: 0, moderateCAGR: 0, bestCAGR: 0 };

  const milestoneData = useMemo(() => {
    const milestones: any[] = [];
    if (!currentHistory || currentHistory.length === 0) return milestones;

    // 역사적 지점 추출
    const historyYears = [2010, 2013, 2016, 2019, 2022, 2024];
    historyYears.forEach(year => {
      const targetPoint = currentHistory.find(d => d.date.startsWith(`${year}-12`)) || 
                          currentHistory.find(d => d.date.startsWith(`${year}`));
      const refPoint = currentReference.find(d => d.date.startsWith(`${year}-12`)) || 
                       currentReference.find(d => d.date.startsWith(`${year}`));

      if (targetPoint) {
        milestones.push({
          date: `${year} YE`,
          reference: refPoint ? refPoint.value : null,
          history: targetPoint.value,
          worst: null,
          moderate: null,
          best: null,
          isHistory: true,
          isBase: false,
          isForecast: false
        });
      }
    });

    // 현재 기준점 (Base)
    const last = currentHistory[currentHistory.length - 1];
    if (last) {
      const lastRef = currentReference.find(d => d.timestamp === last.timestamp) || currentReference[currentReference.length - 1];
      milestones.push({
        date: '2025-06 (Base)',
        reference: lastRef ? lastRef.value : null,
        history: last.value,
        worst: last.value,
        moderate: last.value,
        best: last.value,
        isBase: true,
        isHistory: false,
        isForecast: false
      });
    }

    // 예측 지점 추출 (분기별)
    if (safeAlt1 && safeAlt1.length > 0) {
      const forecastYears = [2026, 2027, 2028, 2029, 2030];
      const quarters = ['03', '06', '09', '12'];
      forecastYears.forEach(year => {
        quarters.forEach(q => {
          const prefix = `${year}-${q}`;
          const idx1 = safeAlt1.find(d => d.date.startsWith(prefix));
          const idx2 = safeAlt2.find(d => d.date.startsWith(prefix));
          const idx3 = safeAlt3.find(d => d.date.startsWith(prefix));
          if (idx1 && idx2 && idx3) {
            milestones.push({
              date: prefix,
              reference: null,
              history: null,
              worst: idx1.value,
              moderate: idx2.value,
              best: idx3.value,
              isForecast: true,
              isHistory: false,
              isBase: false
            });
          }
        });
      });
    }
    return milestones;
  }, [currentHistory, currentReference, safeAlt1, safeAlt2, safeAlt3]);

  const getLatestValue = (arr: DataPoint[]) => (arr && arr.length > 0) ? arr[arr.length - 1].value : 0;
  const baselineValue = getLatestValue(currentHistory);
  const getChangePercent = (curr: number) => !baselineValue ? 0 : ((curr - baselineValue) / baselineValue) * 100;

  return (
    <div className="min-h-screen bg-slate-50 pb-10 font-sans text-slate-900">
      <header className="bg-white border-b border-slate-200 sticky top-0 z-50 py-2">
        <div className="max-w-7xl mx-auto px-4 flex flex-col md:flex-row md:items-center justify-between">
          <div className="flex flex-col">
             <div className="flex items-center gap-2">
                <div className="w-5 h-5 bg-indigo-900 rounded flex items-center justify-center text-white font-black text-[10px]">KU</div>
                <h1 className="font-black text-sm tracking-tight text-slate-900 uppercase">Korea Value-Up Simulator</h1>
             </div>
          </div>
          <div className="mt-2 md:mt-0 text-right">
             <p className="text-[9px] font-black text-indigo-600 bg-indigo-50 px-2 py-1 rounded-full inline-block border border-indigo-100">
                INTEGRATED 7-FACTOR ENGINE
             </p>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 py-4">
        <ControlPanel config={config} setConfig={setConfig} onRunSimulation={handleManualRun} />

        {/* 상단 스코어카드 */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-4">
          <div className="bg-white py-3 px-5 rounded-xl border border-slate-200 shadow-sm relative overflow-hidden group">
            <div className="absolute top-0 left-0 w-1 h-full bg-rose-400"></div>
            <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Value Trap</h3>
            <div className="flex items-baseline gap-2">
              <span className="text-2xl font-black text-slate-800 tracking-tighter">
                {safeAlt1.length > 0 ? Math.round(getLatestValue(safeAlt1)).toLocaleString() : '-'}
              </span>
              <span className={`text-xs font-bold ${getChangePercent(getLatestValue(safeAlt1)) >= 0 ? 'text-emerald-500' : 'text-rose-500'}`}>
                {getChangePercent(getLatestValue(safeAlt1)).toFixed(1)}%
              </span>
            </div>
            <p className="text-[9px] text-slate-400 mt-1">Est. Ann: {(safeMetrics.worstCAGR * 100).toFixed(1)}%</p>
          </div>

          <div className="bg-white py-3 px-5 rounded-xl border border-indigo-200 shadow-md relative overflow-hidden">
            <div className="absolute top-0 left-0 w-1 h-full bg-indigo-600"></div>
            <h3 className="text-[10px] font-black text-indigo-600 uppercase tracking-widest mb-1">Base Re-rating</h3>
            <div className="flex items-baseline gap-2">
              <span className="text-2xl font-black text-slate-900 tracking-tighter">
                {safeAlt2.length > 0 ? Math.round(getLatestValue(safeAlt2)).toLocaleString() : '-'}
              </span>
              <span className="text-xs font-bold text-emerald-600">
                +{getChangePercent(getLatestValue(safeAlt2)).toFixed(1)}%
              </span>
            </div>
            <p className="text-[9px] text-indigo-400 mt-1">Est. Ann: {(safeMetrics.moderateCAGR * 100).toFixed(1)}%</p>
          </div>

          <div className="bg-white py-3 px-5 rounded-xl border border-slate-200 shadow-sm relative overflow-hidden">
            <div className="absolute top-0 left-0 w-1 h-full bg-emerald-500"></div>
            <h3 className="text-[10px] font-black text-emerald-600 uppercase tracking-widest mb-1">Full Convergence</h3>
            <div className="flex items-baseline gap-2">
              <span className="text-2xl font-black text-slate-800 tracking-tighter">
                {safeAlt3.length > 0 ? Math.round(getLatestValue(safeAlt3)).toLocaleString() : '-'}
              </span>
              <span className="text-xs font-bold text-emerald-600">
                +{getChangePercent(getLatestValue(safeAlt3)).toFixed(1)}%
              </span>
            </div>
            <p className="text-[9px] text-emerald-500 mt-1">Est. Ann: {(safeMetrics.bestCAGR * 100).toFixed(1)}%</p>
          </div>
        </div>

        {/* 메인 시계열 차트 */}
        <div className="bg-white p-3 rounded-2xl shadow-xl border border-slate-200 overflow-hidden mb-6">
          <SimulationChart 
            historyData={currentHistory} referenceData={currentReference}
            referenceMarket={config.referenceMarket} targetIndex={config.targetIndex}
            alt1Data={safeAlt1} alt2Data={safeAlt2} alt3Data={safeAlt3}
          />
        </div>

        {/* 마일스톤 차트 (표 데이터 기반) */}
        {milestoneData && milestoneData.length > 0 && (
          <MilestoneChart data={milestoneData} targetIndex={config.targetIndex} />
        )}

        {/* 상세 데이터 테이블 */}
        {milestoneData && milestoneData.length > 0 && (
          <DataTable 
            milestoneData={milestoneData}
            referenceMarket={config.referenceMarket}
            targetIndex={config.targetIndex}
          />
        )}
      </main>
    </div>
  );
};

export default function App() {
  return (
    <ErrorBoundary>
      <AppContent />
    </ErrorBoundary>
  );
}

