const calculateLSTMNextStep = (prevVal: number, drift: number, volatility: number, momentum: number): { val: number, momentum: number } => {
    const noise = randomNormal(0, volatility);
    const newMomentum = (momentum * 0.75) + (drift * 0.25) + (noise * 0.15); 
    const step = newMomentum * prevVal;
    return { val: prevVal + step, momentum: newMomentum };
};

const calculateBoostingNextStep = (prevVal: number, drift: number, volatility: number): number => {
    const noise = randomNormal(0, volatility);
    let jump = 0;
    if (Math.random() > 0.90) jump = (Math.random() - 0.5) * volatility * 4.0;
    return prevVal * (1 + drift + noise + jump);
};

const calculateStandardNextStep = (prevVal: number, drift: number, volatility: number): number => {
    const noise = randomNormal(0, volatility);
    return prevVal * (1 + drift + noise);
};

export const runSimulation = (
  historyData: DataPoint[], 
  config: SimulationConfig
): { alt1: DataPoint[], alt2: DataPoint[], alt3: DataPoint[], metrics: SimulationMetrics } => {
  const alt1: DataPoint[] = []; 
  const alt2: DataPoint[] = []; 
  const alt3: DataPoint[] = []; 

  if (!historyData || historyData.length === 0) return { alt1, alt2, alt3, metrics: { worstCAGR: 0, moderateCAGR: 0, bestCAGR: 0 } };

  // 2025년 12월 31일을 시뮬레이션 시작점으로 고정
  const lastPoint = historyData[historyData.length - 1];
  const startValue = lastPoint.value;
  const startDate = new Date(2025, 11, 31); 
  const toWeeklyRate = (annualRate: number) => Math.pow(1 + annualRate, 1/52) - 1;

  let annualBaseGrowth = 0.08; 
  let volatilityRef = 0.04; 
  switch (config.referenceMarket) {
    case 'Japan': annualBaseGrowth = 0.10; volatilityRef = 0.04; break;
    case 'Taiwan': annualBaseGrowth = 0.12; volatilityRef = 0.055; break;
    case 'SP500': annualBaseGrowth = 0.11; volatilityRef = 0.035; break;
    case 'NASDAQ': annualBaseGrowth = 0.15; volatilityRef = 0.06; break;
    case 'DowJones': annualBaseGrowth = 0.09; volatilityRef = 0.03; break;
    case 'Germany': annualBaseGrowth = 0.085; volatilityRef = 0.04; break;
  }

  const RISK_FREE_RATE = 0.032;
  const SMB_PREMIUM = 0.025;
  const RMW_PREMIUM = 0.035;
  const CMA_PREMIUM = 0.028;
  const HML_PREMIUM = 0.032;
  const QMJ_PREMIUM = 0.045; 
  const POLICY_PREMIUM = 0.030;

  const marketPremium = annualBaseGrowth - RISK_FREE_RATE;
  const simVol = (volatilityRef / 2.0) * (config.volatility / 5.0);
  const totalWeeks = Math.floor(config.durationMonths * 4.345); 

  let val1 = startValue, val2 = startValue, val3 = startValue;
  let m1 = 0, m2 = 0, m3 = 0;

  const isFiveFactor = config.modelType === 'FamaFrench5';
  const effectiveQmjWeight = isFiveFactor ? 0 : config.qmjWeight;
  const effectivePolicyWeight = isFiveFactor ? 0 : config.policyWeight;

  const worstAnn = RISK_FREE_RATE + (0.75 * marketPremium) - (0.3 * SMB_PREMIUM);
  const moderateAnn = RISK_FREE_RATE + (config.betaWeight * marketPremium) + (config.smbWeight * SMB_PREMIUM) + (config.hmlWeight * HML_PREMIUM) + (config.rmwWeight * RMW_PREMIUM) + (effectiveQmjWeight * QMJ_PREMIUM) + (effectivePolicyWeight * POLICY_PREMIUM);
  const bestAnn = moderateAnn + 0.025;

  for (let i = 1; i <= totalWeeks; i++) {
    const newDate = new Date(startDate);
    newDate.setDate(startDate.getDate() + (i * 7));
    const dStr = formatDate(newDate); 
    const ts = newDate.getTime();

    const lambda = Math.min(1.0, 0.4 + (i / totalWeeks) * 0.6);

    const d1 = toWeeklyRate(worstAnn);
    const d2 = toWeeklyRate(moderateAnn * (0.8 + 0.2 * lambda));
    const d3 = toWeeklyRate(bestAnn * (0.7 + 0.3 * lambda));

    if (config.modelType === 'LSTM' || config.modelType === 'GRU') {
        const r1 = calculateLSTMNextStep(val1, d1, simVol * 0.9, m1); val1 = r1.val; m1 = r1.momentum;
        const r2 = calculateLSTMNextStep(val2, d2, simVol * 0.9, m2); val2 = r2.val; m2 = r2.momentum;
        const r3 = calculateLSTMNextStep(val3, d3, simVol * 0.9, m3); val3 = r3.val; m3 = r3.momentum;
    } else if (config.modelType === 'XGBoost' || config.modelType === 'LightGBM') {
        val1 = calculateBoostingNextStep(val1, d1, simVol * 1.2);
        val2 = calculateBoostingNextStep(val2, d2, simVol * 1.2);
        val3 = calculateBoostingNextStep(val3, d3, simVol * 1.2);
    } else {
        val1 = calculateStandardNextStep(val1, d1, simVol);
        val2 = calculateStandardNextStep(val2, d2, simVol);
        val3 = calculateStandardNextStep(val3, d3, simVol);
    }

    alt1.push({ date: dStr, timestamp: ts, value: val1, type: 'Prediction', scenario: 'alt1_worst' });
    alt2.push({ date: dStr, timestamp: ts, value: val2, type: 'Prediction', scenario: 'alt2_moderate' });
    alt3.push({ date: dStr, timestamp: ts, value: val3, type: 'Prediction', scenario: 'alt3_best' });
  }

  return { 
    alt1, alt2, alt3, 
    metrics: { worstCAGR: worstAnn, moderateCAGR: moderateAnn, bestCAGR: bestAnn } 
  };
};

